local cjson = require "cjson"
local xml = require "xml"

local function parse_xml_with_entities(xml_string)
    local entity_map = {
        ["&lt;"] = "<",
        ["&gt;"] = ">",
        ["&amp;"] = "&",
        ["&quot;"] = '"',
        ["&apos;"] = "'",
        ["&#(%d+);"] = function(n) return string.char(tonumber(n)) end,
        ["&#x(%x+);"] = function(n) return string.char(tonumber(n, 16)) end
    }
    
    local function decode_entities(str)
        for pattern, replacement in pairs(entity_map) do
            if type(replacement) == "function" then
                str = str:gsub(pattern, replacement)
            else
                str = str:gsub(pattern, replacement)
            end
        end
        return str
    end
    
    xml_string = decode_entities(xml_string)
    
    local success, parsed = pcall(xml.load, xml_string)
    if not success then
        return nil, "Failed to parse XML: " .. tostring(parsed)
    end
    
    return parsed, nil
end

local function xml_to_table(node)
    if type(node) ~= "table" then
        return node
    end
    
    local result = {}
    
    if node[0] then
        result._tag = node[0]
    end
    
    for k, v in pairs(node) do
        if type(k) == "number" then
            if type(v) == "table" then
                local tag = v[0]
                if tag then
                    if not result[tag] then
                        result[tag] = {}
                    end
                    table.insert(result[tag], xml_to_table(v))
                end
            elseif type(v) == "string" then
                if not result._text then
                    result._text = v
                else
                    result._text = result._text .. v
                end
            end
        elseif k ~= 0 then
            result[k] = v
        end
    end
    
    for k, v in pairs(result) do
        if type(v) == "table" and #v == 1 and k ~= "_tag" then
            result[k] = v[1]
        end
    end
    
    return result
end

local function extract_soap_body(parsed_xml)
    local soap_body = nil
    
    local function find_body(node)
        if type(node) ~= "table" then
            return nil
        end
        
        if node[0] and (node[0]:match("Body$") or node[0]:lower():match("body$")) then
            return node
        end
        
        for k, v in pairs(node) do
            if type(k) == "number" and type(v) == "table" then
                local found = find_body(v)
                if found then
                    return found
                end
            end
        end
        
        return nil
    end
    
    soap_body = find_body(parsed_xml)
    
    if soap_body then
        return xml_to_table(soap_body)
    end
    
    return xml_to_table(parsed_xml)
end

local function get_request_body()
    ngx.req.read_body()
    local body = ngx.req.get_body_data()
    
    if not body then
        local body_file = ngx.req.get_body_file()
        if body_file then
            local file = io.open(body_file, "r")
            if file then
                body = file:read("*all")
                file:close()
            end
        end
    end
    
    return body
end

local function send_soap_fault(fault_code, fault_string)
    local soap_fault = string.format([[<?xml version="1.0" encoding="UTF-8"?>
<soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">
  <soap:Body>
    <soap:Fault>
      <faultcode>%s</faultcode>
      <faultstring>%s</faultstring>
    </soap:Fault>
  </soap:Body>
</soap:Envelope>]], fault_code, fault_string)
    
    ngx.status = ngx.HTTP_INTERNAL_SERVER_ERROR
    ngx.header["Content-Type"] = "text/xml; charset=utf-8"
    ngx.say(soap_fault)
    ngx.exit(ngx.HTTP_INTERNAL_SERVER_ERROR)
end

local function main()
    if ngx.req.get_method() ~= "POST" then
        send_soap_fault("soap:Client", "Only POST method is allowed")
        return
    end
    
    local body = get_request_body()
    
    if not body or body == "" then
        send_soap_fault("soap:Client", "Empty request body")
        return
    end
    
    local parsed_xml, err = parse_xml_with_entities(body)
    
    if not parsed_xml then
        send_soap_fault("soap:Client", "Invalid XML: " .. (err or "unknown error"))
        return
    end
    
    local soap_data = extract_soap_body(parsed_xml)
    
    ngx.ctx.soap_data = soap_data
    ngx.ctx.parsed_xml = parsed_xml
    
    ngx.log(ngx.INFO, "Parsed SOAP request: ", cjson.encode(soap_data))
    
    ngx.header["Content-Type"] = "application/json"
    ngx.say(cjson.encode({
        success = true,
        data = soap_data
    }))
end

main()